  if (personalUse.length > 0) return { grade: 'C', label: '低价值', reason: '个人自用', auto: true };

  // ─── B 级（默认）───
  // 有实质对话但信息不足
  if (realMsgs >= 5 && customerMsgs >= 2)
    return { grade: 'B', label: '普通客户', reason: '信息不足自动定B', auto: true };

