  professional:    [],   // 沟通专业度标记（长消息/多轮细节讨论）

  // C级候选
  personalUse:     [],   // 个人自用/送礼
  smallQty:        [],   // <= 30 件
  oneTime:         [],   // 一次性采购标记
  scattered:       [],   // 行为散漫 — 问完消失

  // D级候选
  irrelevantProduct: [], // 品类完全不匹配（成人服装等）
  nonProcurement:  [],   // 非采购意图（问转让/加盟/找工作）
  spamRubbish:     [],   // 误入/垃圾询盘

  // 辅助
  orderHistory:    [],   // 历史订单记录（数量+金额）
  totalQtyMentioned: 0,  // 全对话提到的最高数量
};
```

### 3.2 信号检测正则表（按等级分组）

在消息循环中，对每条客户真实消息执行以下检测：

**S 级检测：**
```javascript
// 品牌/ODM/定制包装
/品牌|brand|odm|oem|logo|label|custom[\s-]?(made|packag|design|tag)|hangtag|barcode|private[\s-]?label|own[\s-]?(brand|design|label)|定制|贴牌|吊牌|条码/i
// 分销渠道
/amazon|walmart|shopify|retail[\s-]?chain|distribut|wholesale[\s-]?channel|连锁|零售网|代理/i
// 大批量 >= 500
/(?:[5-9]\d{2,}|[1-9]\d{3,})\s*(?:pcs|pieces|units|件|sets)/i
// 复购
/re-?order|again.*order|repeat|复购|多次|another.*order/i
// 公司资料
/website|官网|store.*link|shop.*link|company[\s-]?name|business[\s-]?card|catalog.*website/i
```

**A 级检测：**
```javascript
// 批发商/零售商身份
/wholesale|批发|retailer|retail[\s-]?store|reseller|分销|distributor|importer|进口商/i
// 中等批量 200-500
/(?:[2-4]\d\d|500)\s*(?:pcs|pieces|units|件|sets)/i
// 定制/OEM 需求
/oem|odm|custom|定制|own[\s-]?(design|label|brand)|logo/i
// 样品已寄出
/sample[\s-]?(sent|shipped|received|收到)|样品.*(寄|发|到)/i
// MOQ确认
/moq.*(ok|fine|good|accept|500|可以|没问题)/i
```

**C 级检测：**
```javascript
// 个人自用
/for[\s-]?(myself|my[\s-]?(kid|baby|child|family))|personal[\s-]?use|自用|送人|gift|礼物/i
// 极小量 <= 30
/(?:\b[1-2]?\d\b|30)\s*(?:pcs|pieces|units|件)/i
// 行为散漫
// (通过 realMsgs 低 + 长时间未回 间接判定，不靠关键词)
```

**D 级检测：**
```javascript
// 品类不匹配
/adult|成人|men[\s-]?wear|women[\s-]?wear|not[\s-]?(baby|kid|child|infant)/i
// 非采购
/转让|franchise|加盟|找工|job[\s-]?(offer|hunt)/i
```

### 3.3 重写 `determineQuality()` 函数

**输入变更**：从 `e` → `(e, qualitySignals, realMsgs, customerMsgs, hasPrice, hasSample, hasQuantity)`

**判定逻辑**（按 classification-rules.md 第 61-107 行硬判定标准）：

```javascript
function determineQuality(e, signals, realMsgs, customerMsgs, hasPrice, hasSample, hasQuantity) {
  const { brandOem, channel, bulk500plus, repeatOrder, companyInfo, largeCompany,
          wholesaleRetail, bulk200to500, customOem, sampleSent, moqConfirmed, professional,
          personalUse, smallQty, oneTime,
          irrelevantProduct, nonProcurement, spamRubbish,
          orderHistory, totalQtyMentioned } = signals;

  // ─── D 级（优先判定，排除无价值客户）───
  const dReasons = [];
  if (irrelevantProduct.length > 0) dReasons.push('品类不匹配');
  if (realMsgs <= 2 && customerMsgs === 0) dReasons.push('仅系统消息/无真实对话');
  if (nonProcurement.length > 0) dReasons.push('非采购意图');
  if (spamRubbish.length > 0) dReasons.push('垃圾询盘');

  if (dReasons.length >= 2) return { grade: 'D', label: '无关/废弃', reason: dReasons.join('+'), auto: true };
  if (irrelevantProduct.length > 0 && realMsgs <= 5 && customerMsgs <= 2)
    return { grade: 'D', label: '无关', reason: '品类不匹配+低互动', auto: true };

  // ─── S 级判定（满足任意一条）───
  const sReasons = [];

  // 1) 品牌商/ODM + 首单>=500件 + 定制包装/吊牌/条码
  if (brandOem.length > 0 && bulk500plus.length > 0)
    sReasons.push('品牌ODM+大批量(≥500)');

  // 2) 有明确分销渠道
  if (channel.length > 0)
    sReasons.push('分销渠道: ' + channel.map(c => c.snippet).join('; '));

  // 3) 复购 >= 1000件或 >= $3000
  if (repeatOrder.length > 0 || orderHistory.some(h => h.qty >= 1000 || h.amount >= 3000))
    sReasons.push('复购/累计大单');

  // 4) 客户主动提供官网/店铺链接/公司资料 + 有其他 S/A 信号
  if (companyInfo.length > 0 && (brandOem.length > 0 || channel.length > 0 || bulk500plus.length > 0))
    sReasons.push('公司资料+' + (brandOem.length > 0 ? '品牌' : channel.length > 0 ? '渠道' : '大批量'));

  if (sReasons.length > 0) return { grade: 'S', label: '战略客户', reason: sReasons.join(' | '), auto: true };

  // ─── A 级判定 ───
  const aReasons = [];

  // 1) 批发商/零售商 + 明确批量>=200 + 沟通专业
  if (wholesaleRetail.length > 0 && bulk200to500.length > 0)
    aReasons.push('批发身份+批量≥200');

  // 2) 批发商 + 200-500件现货大单
  if (wholesaleRetail.length > 0 && bulk500plus.length > 0)
    aReasons.push('批发身份+大批量');

  // 3) 定制/OEM + 认真反复沟通细节
  if (customOem.length > 0 && professional.length > 0)
    aReasons.push('定制需求+沟通专业');

  // 4) 已成交客户 首单200-500
  if (orderHistory.length > 0 && orderHistory.some(h => h.qty >= 200 && h.qty <= 500))
    aReasons.push('已成交(200-500件)');

  // 5) 样品已寄出 等待反馈
  if (sampleSent.length > 0)
    aReasons.push('样品已寄出等反馈');

  // 6) 已接受MOQ 500 + 在谈价格
  if (moqConfirmed.length > 0 && hasPrice)
    aReasons.push('已接受MOQ在谈价格');

  if (aReasons.length > 0) return { grade: 'A', label: '优质客户', reason: aReasons.join(' | '), auto: true };

  // ─── 单信号预升级（品牌/渠道/大批量 任一条 → A 待验证）───
  if (brandOem.length > 0) return { grade: 'A', label: '优质客户', reason: '品牌/ODM信号(待验证更多)', auto: true };
  if (channel.length > 0) return { grade: 'A', label: '优质客户', reason: '渠道信号(待验证更多)', auto: true };
  if (bulk500plus.length > 0) return { grade: 'A', label: '优质客户', reason: '大批量信号(待验证更多)', auto: true };

  // ─── C 级判定 ───
  const cReasons = [];

  // 1) 个人自用 + <=30件
  if (personalUse.length > 0 && smallQty.length > 0)
    cReasons.push('个人自用+极小量');
  else if (personalUse.length > 0)
    cReasons.push('个人自用');

  // 2) 一次性采购
  if (oneTime.length > 0) cReasons.push('一次性采购');

  // 3) 行为散漫（问完消失 + 长时间无互动 + 对话少）
  if (realMsgs <= 4 && customerMsgs <= 2 && e.lastCustomerMsgDays !== '-' && e.lastCustomerMsgDays > 30 && !hasPrice && !hasSample)
    cReasons.push('行为散漫(低互动+长期不活跃)');

  if (cReasons.length >= 2) return { grade: 'C', label: '低价值', reason: cReasons.join('+'), auto: true };
  if (personalUse.length > 0) return { grade: 'C', label: '低价值', reason: '个人自用', auto: true };

  // ─── B 级（默认）───
  // 有实质对话但信息不足
  if (realMsgs >= 5 && customerMsgs >= 2)
    return { grade: 'B', label: '普通客户', reason: '信息不足自动定B', auto: true };

  if (hasPrice || hasSample || hasQuantity)
    return { grade: 'B', label: '普通客户', reason: '有实质讨论但规模未知', auto: true };

  // ─── 信息极度不足 ───
  return { grade: 'B', label: '普通客户', reason: '信息不足默认B【需你决策】', auto: true, needsReview: true };
}
```

### 3.4 修改消息循环（核心改动）

在现有消息循环（第 136-160 行）中，增加质量信号检测：

```javascript
for (const m of msgs) {
  const msg = m.message || m;
  const uid = msg.sender && msg.sender.uid || '';
  const text = getText(msg.content);
  const date = msg.createAt || '';
  if (isSys(msg.content)) { sysMsgs++; continue; }

  if (uid === OUR_UID) { ourMsgs++; ... }
  else if (uid) { customerMsgs++; ... }

  const lc = text.toLowerCase();
  // ... 现有 flag detection (hasPI, hasAddress, etc.) ...

  // ★ 新增：全量质量信号累加（方案A）
  if (uid && uid !== OUR_UID) { // 仅客户消息
    const snippet = text.substring(0, 120);
    if (/品牌|brand|odm|oem|logo|label|custom[\s\-]?(made|packag|design|tag)|hangtag|barcode|private[\s\-]?label|own[\s\-]?(brand|design|label)|定制|贴牌|吊牌|条码/i.test(text))
      qualitySignals.brandOem.push({ msgIdx: i, snippet });

    if (/amazon|walmart|shopify|retail[\s\-]?chain|连锁|零售网|代理.*网络|distribut.*network/i.test(text))
      qualitySignals.channel.push({ msgIdx: i, snippet });

    if (/([5-9]\d{2,}|[1-9]\d{3,})\s*(pcs|pieces|units|件|sets)/i.test(text))
      qualitySignals.bulk500plus.push({ msgIdx: i, snippet });

    // ... 其余信号检测同上模式 ...
  }
}
```

### 3.5 判定优先级（硬规则）

```
D 级优先（不匹配 → 排除）
  ↓
S 级（满足任一条硬标准）
  ↓
A 级（满足任一条硬标准）
  ↓
单信号预升级到 A（品牌/渠道/大批量 任一 ≥ 1条）
  ↓
C 级（满足两条C信号 或 明确个人自用）
  ↓
B 级（默认）
```

### 3.6 【需你决策】标记规则

以下情况输出时标注 `【需你决策】`：
1. 信息极度不足 → 默认 B 级 → 标 `【需你决策】`
2. 单信号触发 A 级（品牌/渠道/大批量 任一 但无第二信号验证） → 标 `【需你决策：可能降级】`
3. 品类不匹配但对话活跃（有真实采购意向）→ 标 `【需你决策：真需求or误入】`
4. 触及 14 条边缘情况中任一条 → 标对应边缘情况编号

### 3.7 输出增强

在控制台输出和 JSON 中增加：
- `gradeReason` 从模糊变为具体信号列表
- 新增 `qualitySignals` 字段，列出检测到的信号类型和来源消息数
- 新增 `needsReview` 字段标记需人工复核的客户

